TurtleRPNewIcons = {}

for _, versionKey in ipairs(TurtleRPIconBatchOrder) do
  local batch = TurtleRPIconBatches[versionKey]
  if batch then
    for i = 1, table.getn(batch) do
      table.insert(TurtleRPNewIcons, batch[i])
    end
  end
end

